Rule.Source:
import sailpoint.object.Identity;
  import sailpoint.object.Custom;
    import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
  import sailpoint.tools.Util;
  import sailpoint.object.ApprovalSet;
  import sailpoint.object.ApprovalItem;
  import sailpoint.object.WorkItem;
  import sailpoint.object.NotificationConfig;
  
  static Log logger = LogFactory.getLog("rule.Ascension-Rule-WorkItemEscalationExpiration");
  
  String RULE_NAME = "Ascension-Rule-WorkItemEscalationExpiration";
  logger.debug("Entered "+RULE_NAME);
  
  String FALLBACK_APPROVER = "IDM Team";
  
   ApprovalSet as = new ApprovalSet();
   ApprovalItem ai = new ApprovalItem();
   as = item.getApprovalSet();
   if(as!=null) {
    for(ApprovalItem ai : as.getItems()) { //Iterating through each approval item to look for datalake groups
  		String ent = ai.getDisplayValue(); //Fetching the group name from the approval item
      logger.debug("Approval item is : "+ai.toXml());
  
      boolean isWorkgroup = false;
     Identity id = context.getObjectByName(Identity.class, ai.getOwner());
   //   logger.debug("Owner is : "+id);
      if (id.isWorkgroup()) { //checking if the approver is a workgroup
        logger.debug("Approver is workgroup");
      	isWorkgroup = true;
      }
      if(ent!=null){
        logger.debug("Requested group is : "+ent);
  				if(ent.startsWith("gcp-tp-data-datalake")) { //check if the name contains the default datalake name
   						logger.debug("The request is for a datalake group so second and third level approval will not be re-assigned after reminders, it has expired");	
    					return null; //do not reassign/escalate the approval
  				}
    		}
     	}
  	}
  
  Custom accessRequestCustom = context.getObjectByName(Custom.class, "Ascension-Custom-AccessRequest");
  if (accessRequestCustom != null && Util.isNotNullOrEmpty(accessRequestCustom.get("DefaultWorkgroup")) ) {
  	FALLBACK_APPROVER = accessRequestCustom.get("DefaultWorkgroup");
  }
  //Expiring approval if already escalated
  if(item.getEscalationCount() > 0) {
    logger.debug("Expiring WorkItem :"+item.getEscalationCount());
    return null;
  }

  Identity newOwner = item.getNotificationOwner(context);
  logger.debug("Item is : "+item.toXml());
  if (newOwner != null) {
   
    newOwner = newOwner.getManager();
  }
  logger.debug("Exiting "+RULE_NAME);
  if (newOwner != null && !newOwner.isInactive()) {
    //logger.debug("Setting new owner as " + newOwner.getName());
	return newOwner.getName();
  }
  else
    return FALLBACK_APPROVER;
